export function transformQuickBooksStatus(response) {
  return {
    connected: response.data.connected,
    realmId: response.data.realm_id,
    expiresAt: response.data.expires_at,
    isExpired: response.data.is_expired
  };
}

export function formatSyncResult(data) {
  return {
    invoicesSynced: data.invoices_synced,
    newInvoices: data.new_invoices,
    updatedInvoices: data.updated_invoices,
    syncTimestamp: data.sync_timestamp
  };
}

export function validateSyncDateRange(startDate, endDate) {
  if (!startDate || !endDate) {
    throw new Error('Start and end dates are required');
  }
  if (new Date(startDate) > new Date(endDate)) {
    throw new Error('Start date must be before end date');
  }
}

